STRINGS.SKIN_DESCRIPTIONS.loading_dragonfly_yule = "Kışın soğuk gecesinde lavlar sıcak yanarken,\nZiyafet Sineği en ateşli uçuşuyla kanatlanır."
STRINGS.SKIN_DESCRIPTIONS.loading_drama = "Kim spot ışıklarına çıkmaya hazır?"
STRINGS.SKIN_DESCRIPTIONS.loading_dst10_signed = "Hayatta kalmanın on yılını kutlayın - ah ne kadar utanç verici, bazı holiganlar üzerine isimlerini karalamışlar!"
STRINGS.SKIN_DESCRIPTIONS.loading_dst10_unsigned = "Constant'ta hayatta kalmanın on yılını kutlayın!"
STRINGS.SKIN_DESCRIPTIONS.loading_eyeofthestorm_trailer = "Constant'ın Kraliçesi'ni bile tedirgin edebilecek çok az şey vardır..."
STRINGS.SKIN_DESCRIPTIONS.loading_farming = "Günler ekim ve zahmetle geçti,\nTohumları toplamak ve toprağı beslemekle,\nUmutla ürünlerin en iyisini vereceğini,\n(Sadece zararlılara karşı dikkatli olduğunuzdan emin olun!)"
STRINGS.SKIN_DESCRIPTIONS.loading_farming2 = "Herkesin çiftçilik yeteneği yoktur."
STRINGS.SKIN_DESCRIPTIONS.loading_feast = "Yemek hazır, masa kuruldu,\nUnutulmaz bir ziyafet için toplanın."
STRINGS.SKIN_DESCRIPTIONS.loading_gameplay_trailer = "Gelecek korkutucu olabilir,\n(Şimdiki zaman da korkutucu)\nAma eğer geçmiş bize bir şey öğrettiyse,\nBirlikte atlatacağız."
STRINGS.SKIN_DESCRIPTIONS.loading_gingersnow = "Hava soğuduğunda ve kar yeri kapladığında, bazen bir zencefilli kurabiye köyü bulunabilir."
STRINGS.SKIN_DESCRIPTIONS.loading_gnarwail = "Deniz birçok tehlike barındırır, her zaman çalkantılı sulara hazırlıklı olmak gerekir."
STRINGS.SKIN_DESCRIPTIONS.loading_goats_victorian = "\"Tahtayı her zaman sabit tutun. Unutmayın, keskin bir bıçak kör bir bıçaktan daha güvenlidir.\nUnutmayın.\""
STRINGS.SKIN_DESCRIPTIONS.loading_goosemoose_yule = "Büyük, tombul bir kaz ziyafet için uygun görünüyor,\nTa ki korkunç canavarın yemeği siz olana kadar."
STRINGS.SKIN_DESCRIPTIONS.loading_grotto = "Sonsuza dek kaçamayacaksın."
STRINGS.SKIN_DESCRIPTIONS.loading_grotto2 = "Ay Adası, ay parçasının denize çarpmasının tek sonucu değildi. Aynı zamanda uzun süredir mühürlenmiş ve unutulmuş mağaraların bir kısmını da ortaya çıkardı. Acaba o noktaya iniş gerçekten bir tesadüf müydü diye merak edilebilir..."
STRINGS.SKIN_DESCRIPTIONS.loading_lunacy = "Zihninizi korkunç yeni olasılıklara açın."
STRINGS.SKIN_DESCRIPTIONS.loading_lunar = "Tedbirli olun, bu dünya dışı ziyaretçiler barışçıl görünmüyor."
STRINGS.SKIN_DESCRIPTIONS.loading_lunarrift = "Bir şey Constant'ın yaratıklarını ele geçiriyor... bu dünyaya ait olmayan bir şey..."
STRINGS.SKIN_DESCRIPTIONS.loading_magma = "Savaş Ustası Pugna, savaşçıları taştan ve ateşten dövülmüş Savaş Arenası'nın kaprislerine maruz bırakmaktan büyük zevk alır."
STRINGS.SKIN_DESCRIPTIONS.loading_magma2 = "Ateşli Ocak'tan kaçmak için, Hayatta Kalanlarımız Savaş Ustası Pugna'nın korkunç şampiyonlarına karşı savaşta zafer kazanmalı."
STRINGS.SKIN_DESCRIPTIONS.loading_march_qol = "Önemli olan düşüncedir."
STRINGS.SKIN_DESCRIPTIONS.loading_maxwell = "Maxwell'in Kabus Tahtı'ndaki uzun saltanatı onu henüz tam olarak anlaşılamayan şekillerde değiştirdi. Sonuç olarak, Codex Umbra adlı kitabına büyük ölçüde güvenmeye devam ediyor."
STRINGS.SKIN_DESCRIPTIONS.loading_maxwell2 = "Maxwell, kendi kurallarına uyan bir dünyaya oldukça alışmıştı... ama şimdi ipleri başka biri çekiyor."
STRINGS.SKIN_DESCRIPTIONS.loading_merm = "Merm'ler, Constant'ın bataklıklarında insanlardan çok önce yaşadı ve muhtemelen onlardan çok sonra da var olacaklar."
STRINGS.SKIN_DESCRIPTIONS.loading_newhorizons = "Önünüzdeki yol uzun ve tehlikeli, ama şimdi geri dönmek için çok uzağa geldiniz."
STRINGS.SKIN_DESCRIPTIONS.loading_pig_elite = "Domuz Kralı'nın dört elit savaşçısı, kazançlarının yarısını yuvarlanacak çamuru olmayan zavallı talihsiz domuzlara verir."
STRINGS.SKIN_DESCRIPTIONS.loading_pigking = "Efsaneye göre Domuz Kralı ve takipçileri, Constant'ta özgürce hükmetmek için evlerini çok uzun zaman önce terk ettiler."
STRINGS.SKIN_DESCRIPTIONS.loading_piglio1 = "Aşk en beklenmedik yerlerde bulunabilir."
STRINGS.SKIN_DESCRIPTIONS.loading_piglio2 = "Düşmanımın düşmanı dostumdur... ya da belki daha fazlası?"
STRINGS.SKIN_DESCRIPTIONS.loading_piglio3 = "Bir merm ve bir domuz, kendilerini kurtarmak için farklılıklarını bir kenara bırakabilir mi?"
STRINGS.SKIN_DESCRIPTIONS.loading_piglio4 = "Hiçbir şey romantik bir anı aç örümcek sürüsü kadar mahvedemez."
STRINGS.SKIN_DESCRIPTIONS.loading_piglio5 = "Bu sürü kışkırtılmış ve saldırıya geçmiş durumda!"
STRINGS.SKIN_DESCRIPTIONS.loading_piglio6 = "Merm'ler şiddetle bölgeseldir ve kendi bölgelerine hiçbir yabancının girmesine izin vermezler."
STRINGS.SKIN_DESCRIPTIONS.loading_piglio7 = "Bir domuzun çamurda rahatlatıcı bir banyodan daha çok sevdiği çok az şey vardır."
STRINGS.SKIN_DESCRIPTIONS.loading_pirates1 = "Açık denizde yelken açmak istersen, Ay Koyu'nun korsanlarına dikkat etsen iyi olur!"
STRINGS.SKIN_DESCRIPTIONS.loading_rainingfrog = "Yılın bu zamanı için alışılmadık derecede kurbağalı."
STRINGS.SKIN_DESCRIPTIONS.loading_roadmap = "Tünelin sonunda bir ışık olabilir mi?"
STRINGS.SKIN_DESCRIPTIONS.loading_roadmap2 = "Ay adasında kamp kurmaya cesaret eden Hayatta Kalanlar, genellikle tuhaf hayaletler tarafından ziyaret edildiklerini iddia ederler."
STRINGS.SKIN_DESCRIPTIONS.loading_shadow = "Constant'ın en karanlık derinliklerinde hangi dehşetler gizleniyor?"
STRINGS.SKIN_DESCRIPTIONS.loading_shadow2 = "Ağaçlar karşılık vermez, ama Ağaç Muhafızları verir."
STRINGS.SKIN_DESCRIPTIONS.loading_shadowrift = "\"Onu serbest bırakmak en iyi fikrim olmayabilir.\""
STRINGS.SKIN_DESCRIPTIONS.loading_terraria_trailer = "Küçücük bir talihsizlik, Terraria dünyasını oldukça... sürekli bir tehlikeye sürükledi ve Constant'ı daha önce hiç olmadığı kadar terörize ediyor! İki dünya çarpıştığında çatlaklardan neyin sızacağını kim bilebilir?"
STRINGS.SKIN_DESCRIPTIONS.loading_triplethreat = "Kötü şans üçer üçer gelir, Mürekkep Lekeleri de öyle."
STRINGS.SKIN_DESCRIPTIONS.loading_walter_trailer = "Dostluk en beklenmedik yerlerde bulunabilir."
STRINGS.SKIN_DESCRIPTIONS.loading_walter_trailer2 = "Böyle bir gecede, insan yalnız seyahat etmek istemez."
STRINGS.SKIN_DESCRIPTIONS.loading_wanda1 = "Zaman içinde ileri geri seyahat etmek bir süre sonra kafa karıştırıcı hale gelir. Birden fazla zaman çizelgesinin olaylarını hatırlamaya çalışmak, insanı biraz dağınık gösterebilir."
STRINGS.SKIN_DESCRIPTIONS.loading_wanda_trailer = "Wanda, hatırlayabildiğinden daha uzun süredir geleceğinden kaçmaya çalışıyor - ancak bir saniyelik bir karar onu Constant'ın zaman akışına dolandırdıktan sonra, nihayet ona yetişen geçmişi olabilir..."
STRINGS.SKIN_DESCRIPTIONS.loading_warly2_trailer = "Bazı anılar asla sizi terk etmez.\nWarly için bunlar, eski bir aile tarifinin kokusu ve sevgili annesinin kucaklamalarının sıcaklığıdır."
STRINGS.SKIN_DESCRIPTIONS.loading_warly_trailer = "Warly, sevgili annesinin tatlı gülümsemesini tekrar göreceği umudunu asla yitirmeyecek."
STRINGS.SKIN_DESCRIPTIONS.loading_waterlogged = "Bu devasa okyanus ağaçları, açık denizin tehlikelerinden bir anlık soluklanma sunabilir, ancak Constant'ta hiçbir yer uzun süre gerçekten güvenli değildir."
STRINGS.SKIN_DESCRIPTIONS.loading_waterlogged_trailer = "Drift Wood'un Ulu Ağacı'nın rahatlatıcı gölgesinde yelken açarken, yukarıda sallanan tehlikeyi unutmak çok kolaydır."
STRINGS.SKIN_DESCRIPTIONS.loading_waxwell = "Herkes yerini alsın, Muhteşem Maxwell'in bir sonraki gösterisi başlamak üzere."
STRINGS.SKIN_DESCRIPTIONS.loading_webber = "Webber, eşsiz durumunu kolayca bir rahatsızlık veya lanet olarak görebilirdi. Bunun yerine, bunu ikinci bir şans olarak görmeyi seçti ve bunu boşa harcamamaya kararlı."
STRINGS.SKIN_DESCRIPTIONS.loading_webber2 = "Bugünlerde Webber'ın bir arkadaş bulmak için uzağa gitmesine gerek yok."
STRINGS.SKIN_DESCRIPTIONS.loading_webber_feast = "\"Herkese aldığımız hediyeleri açarken izlemek için çok heyecanlıyız.\""
STRINGS.SKIN_DESCRIPTIONS.loading_webber_sad = "İyi dinleyin çocuklar ve ebeveynlerinizin uyarılarına dikkat edin... yaramazlık sonunda her zaman sizi ısırır."
STRINGS.SKIN_DESCRIPTIONS.loading_webber_trailer = "Bazı şeyler basitçe geri alınamaz."
STRINGS.SKIN_DESCRIPTIONS.loading_wendy = "Wendy, kız kardeşinin ölümüyle ilgili kederine şiddetle tutunur, çünkü ilerlemenin Abigail'in anısının solmasına neden olacağından korkar."
STRINGS.SKIN_DESCRIPTIONS.loading_wendy_blogpostart = "\"Hala oradasın, Abigail... yakında tekrar birlikte oynayabileceğiz.\""
STRINGS.SKIN_DESCRIPTIONS.loading_wendy_creepy = "Ölüme olan tek takıntısından kaçamaz.\nSiz de kaçamazsınız."
STRINGS.SKIN_DESCRIPTIONS.loading_wendy_trailer = "Abigail her zaman Wendy'nin yüzüne bir gülümseme getirmeyi başarırdı... ne yazık ki, daha sonra bu gülümsemenin sonsuza dek kaybolmasının nedeni olacaktı."
STRINGS.SKIN_DESCRIPTIONS.loading_wendy_trailer2 = "Tatlı anılar..."
STRINGS.SKIN_DESCRIPTIONS.loading_wendy_victorian = "Wendy, ayrıntılı yas ritüellerinde garip bir rahatlık bulur.\nBu, yas tutmanın belirsizliğini ortadan kaldırır."
STRINGS.SKIN_DESCRIPTIONS.loading_werepig1 = "Toplanın herkes. Ürkütücü bir hikaye dinlemeye hazır mısınız?"
STRINGS.SKIN_DESCRIPTIONS.loading_werepig2 = "Kamp ateşi hikayeleri, ürkütücü, ay ışıklı gecelerde bir grup arkadaşla en iyi şekilde tadını çıkarır."
STRINGS.SKIN_DESCRIPTIONS.loading_werepig3 = "Kurt domuz sizi akşam yemeğine seve seve davet edecektir."
STRINGS.SKIN_DESCRIPTIONS.loading_werepig4 = "Haksız kazançla elde edilen yiyeceklerin tadını hiçbir şey geçemez."
STRINGS.SKIN_DESCRIPTIONS.loading_werepig5 = "Hadi, kapıyı çal. En kötü ne olabilir ki?"
STRINGS.SKIN_DESCRIPTIONS.loading_werepig6 = "Mezarlığın ortasındaki bu yalnız eski evde kim yaşıyor?"
STRINGS.SKIN_DESCRIPTIONS.loading_wes1 = "Wes, balon sanatlarını icra ederken sık sık kendini kaptırır."
STRINGS.SKIN_DESCRIPTIONS.loading_wes_trailer = "Bu mimin ruh halini açıklamaya çalışmak aptalca bir iş olurdu... aslında bir Nisan şakası."
STRINGS.SKIN_DESCRIPTIONS.loading_wes_trailer2 = "Balonlar, insanın hayal gücünün düşündüğü kadar sağlam değildir."
STRINGS.SKIN_DESCRIPTIONS.loading_wes_trailer3 = "O kader günün başlangıcı, Wes'in kötü şansının kontrolden çıktığı zaman."
STRINGS.SKIN_DESCRIPTIONS.loading_wes_victorian = "Hayatta, birinin işinin o gün için bittiğini bilmekten daha tatmin edici çok az duygu vardır."
STRINGS.SKIN_DESCRIPTIONS.loading_wickerbottom = "Sevindirici bir şekilde, Bayan Wickerbottom, yazılı kelimeye olan tutkusunun yıllar geçtikçe daha da derinleştiğini fark etti. Kağıda dökülen her bilgi, yaşlılığın beyin sislerine karşı dayanıklı hale gelir, bilirsiniz!"
STRINGS.SKIN_DESCRIPTIONS.loading_wickerbottom_victorian = "Bir karga grubuna \"cinayet\" denildiği iyi bilinen bir gerçektir.\nKarga cenazeleri düzenledikleri ise daha az bilinen bir gerçektir."
STRINGS.SKIN_DESCRIPTIONS.loading_wigfrid = "Bir Valkyrie'nin cesareti ve özgüveni Wigfrid'e her zaman doğal gelmedi. Yıllar boyunca, saf irade gücüyle gücünü ve kişiliğini geliştirdi."
STRINGS.SKIN_DESCRIPTIONS.loading_wigfrid_trailer = "Teklif Wigfrid'in kulağına müzik gibi geliyordu..."
STRINGS.SKIN_DESCRIPTIONS.loading_wigfrid_trailer2 = "Kalbin geçmişte kalmışken geleceğe bakmak zor olabilir."
STRINGS.SKIN_DESCRIPTIONS.loading_willow2_trailer = "Aptal olma, bu sadece kötü bir rüya..."
STRINGS.SKIN_DESCRIPTIONS.loading_willow_bats = "Kederli Willow bir balta aldı.\nBir ağaca kırk darbe vurdu."
STRINGS.SKIN_DESCRIPTIONS.loading_willow_trailer = "Willow'un çocukluğu soğuk ve karanlıktı, ta ki içinde bir şey parlayana kadar."
STRINGS.SKIN_DESCRIPTIONS.loading_willow_victorian = "Bazen soğuk ve acı gecelerde, yanan bir kibritin alevinde fantastik görüntüler hayal edilebilir."
STRINGS.SKIN_DESCRIPTIONS.loading_willowfire = "Willow, Sürekli'ye getirilmesini her zaman yeni bir başlangıç olarak görmüştü. Sonuçta her şeyi geride bırakmasına izin vermişti."
STRINGS.SKIN_DESCRIPTIONS.loading_wilson = "Wilson bilime olan sevgisini asla kaybetmedi."
STRINGS.SKIN_DESCRIPTIONS.loading_wilson_feast = "Bilim diyor ki burnunu ısıracağım."
STRINGS.SKIN_DESCRIPTIONS.loading_wilson_madscience = "Bilgi, ruhu beslemek için zihni tüketebilir.\nVe zihni beslemek için ruhu tüketebilir."
STRINGS.SKIN_DESCRIPTIONS.loading_wilson_wagstaff = "İki büyük zihin birleştiğinde, her şey mümkün olabilir."
STRINGS.SKIN_DESCRIPTIONS.loading_winona2_trailer = "Hepsi bağlantılı olmalı... ama nasıl?"
STRINGS.SKIN_DESCRIPTIONS.loading_winona_trailer = "Winona kız kardeşini tekrar göreceğine dair umudunu asla kaybetmedi...\nAma zaman insanları değiştirebilir."
STRINGS.SKIN_DESCRIPTIONS.loading_winona_victorian = "Çekiç sesleri demircinin kulağına müzik gibidir.\nKömür kokusu, tatlı bir parfüm."
STRINGS.SKIN_DESCRIPTIONS.loading_wobot1 = "Bir hurdalık, hurdanın geride bırakıldığı bir yerdir, ne veya kimi bulacağınızı asla bilemezsiniz."
STRINGS.SKIN_DESCRIPTIONS.loading_wobot2 = "Yaratım, yaratıcısının soğuk eleştirel gözüyle yargılanır."
STRINGS.SKIN_DESCRIPTIONS.loading_wobot3 = "Wagstaff, Sürekli'yi kişisel atölyesi ve hurdalığı olarak kullanır."
STRINGS.SKIN_DESCRIPTIONS.loading_wolfgang = "İster topluluklarda ister birliklerde olsun, Wolfgang her zaman yoldaşlık ruhuyla gelişti. Hayatta kalanlara katıldığı günü, şansının nihayet iyiye döndüğü an olarak görüyor."
STRINGS.SKIN_DESCRIPTIONS.loading_wolfgang1 = "Patatesten daha ağır bir şeyi kaldırmak bu... şey, \"güçlü adam\" için zorlu bir mücadele olacak..."
STRINGS.SKIN_DESCRIPTIONS.loading_wolfgang2 = "Bu güçlü adam neredeyse zirveye ulaştı."
STRINGS.SKIN_DESCRIPTIONS.loading_wolfgang3 = "Bu, zirve performansına ulaşmış bir güçlü adamdır."
STRINGS.SKIN_DESCRIPTIONS.loading_wolfgang_feast = "Güçlü bir Kış Ziyafeti Wolfgang'ı daha da güçlü yapar!"
STRINGS.SKIN_DESCRIPTIONS.loading_wolfgang_trailer = "Wolfgang her zaman gücüyle gurur duyardı, ancak utanç verici bir talihsizlik gücünün biraz abartılı olduğunu ortaya çıkarınca, daha güçlü olmak için her fırsatı hevesle kabul etti... kaynağı ne kadar şüpheli olursa olsun."
STRINGS.SKIN_DESCRIPTIONS.loading_woodie2_trailer = "Dikkatli olun, bazı ağaçların kabuğundan çok ısırığı vardır."
STRINGS.SKIN_DESCRIPTIONS.loading_woodie_trailer = "Dikenli çamlar saldırıya geçtiğinde, Sürekli'nin kendi oduncusuna güvenebilirsiniz."
STRINGS.SKIN_DESCRIPTIONS.loading_woodie_victorian = "Ormanda geçen birçok günden sonra, kendini avladığı şeyden ayırmak zor olabilir."
STRINGS.SKIN_DESCRIPTIONS.loading_wormwood2_trailer = "Her hikayenin bir başlangıcı vardır. Her filiz bir zamanlar küçük bir tohumdu."
STRINGS.SKIN_DESCRIPTIONS.loading_wormwood3_trailer = "Orman, birçok büyüleyici bitki ve hayvan türüne ev sahipliği yapar."
STRINGS.SKIN_DESCRIPTIONS.loading_wormwood_trailer = "Wormwood kendini çok yalnız hissetmeye başladığında, her zaman köklerine geri dönebileceğini bilir."
STRINGS.SKIN_DESCRIPTIONS.loading_wortox2_trailer = "Kader dolu bir seçim Wortox'u sonsuza dek değiştirdi."
STRINGS.SKIN_DESCRIPTIONS.loading_wortox_trailer = "Wortox iyi bir şakayı her zaman severdi, ta ki işler çok ileri gidene kadar..."
STRINGS.SKIN_DESCRIPTIONS.loading_wurt_trailer = "Bazıları bataklığın yaşanacak bir yer olmadığını düşünse de, küçük dostumuz Wurt buna katılmıyor."
STRINGS.SKIN_DESCRIPTIONS.loading_wurt_trailer2 = "Soğuk rüzgar uluyor. Ağaçlar uzun ve çıplak duruyor, iskelet dalları kırık bir aya karşı silüet oluşturuyor."
STRINGS.SKIN_DESCRIPTIONS.loading_wx1 = "WX-78, kendini geliştirme fikrini çok ciddiye alıyor."
STRINGS.SKIN_DESCRIPTIONS.loading_wx_magma = "WX-78'in YAKMA konusunda yanıp tutuşan bir ihtiyacı var."
STRINGS.SKIN_DESCRIPTIONS.loading_wx_trailer = "Geçmiş yaşamlarından gelen anıların hücumuyla yüzleştikten sonra, WX-78 hızla işleri kendi ellerine aldı..."
STRINGS.SKIN_DESCRIPTIONS.lucy_broadaxe = "Sadece ona öyle demeyin."
STRINGS.SKIN_DESCRIPTIONS.lucy_chained = "Nereye gidersen git, o da gider."
STRINGS.SKIN_DESCRIPTIONS.lucy_picnic = "Lucy'yi en son ne zaman pikniğe çıkardın?"
STRINGS.SKIN_DESCRIPTIONS.lucy_punk = "Lucy'nin gerçekten keskin bir yanı var."
STRINGS.SKIN_DESCRIPTIONS.lunarmoth_bright = "Tüylerinin sağlıklı ve parlak kalması için Güveci'nizi düzenli olarak fırçaladığınızdan emin olun."
