STRINGS.SKIN_QUOTES.walter_ancient = "Bir sonraki maceramızda nereye gitmeliyiz, Woby?"
STRINGS.SKIN_QUOTES.walter_bee = "Belki onlar gibi giyinirsem beni sokmazlar!"
STRINGS.SKIN_QUOTES.walter_bee_d = "Belki onlar gibi giyinirsem beni sokmazlar!"
STRINGS.SKIN_QUOTES.walter_bee_p = "Belki onlar gibi giyinirsem beni sokmazlar!"
STRINGS.SKIN_QUOTES.walter_detective = "Endişelenmeyin baylar ve bayanlar, Woby ve ben iş başındayız!"
STRINGS.SKIN_QUOTES.walter_formal = "Daha sık giyerdim ama tüm bu rozetlerle çok ağır..."
STRINGS.SKIN_QUOTES.walter_ice = "Brrr... neyse ki senin zaten kendi kışlık kürkün var, Woby!"
STRINGS.SKIN_QUOTES.walter_lunar = "Kötüler dikkat, ay benim tarafımda!"
STRINGS.SKIN_QUOTES.walter_nature = "Her hikayenin korkusuz bir maceracıya ve güvenilir atına ihtiyacı vardır!"
STRINGS.SKIN_QUOTES.walter_rose = "Sanırım gerçekten duruma ayak uydurdum! Değil mi, Woby?"
STRINGS.SKIN_QUOTES.walter_shadow = "Ne yapacağımı söyleyen bir el kitabına ihtiyacım yok - kuralları şimdi ben koyuyorum!"
STRINGS.SKIN_QUOTES.walter_survivor = "Umarım üniformamın durumu yüzünden puan kaybetmem."
STRINGS.SKIN_QUOTES.walter_ventriloquist = "Gerçekten korkunç bir hikaye dinlemek ister misin?"
STRINGS.SKIN_QUOTES.walter_victorian = "Ekstra, ekstra! Hepsini okuyun!"
STRINGS.SKIN_QUOTES.walter_yule = "Hadi Woby, o Kış Ziyafeti ağacı kendini süslemeyecek!"
STRINGS.SKIN_QUOTES.wanda_bishop = "Bu maç birkaç erteleme daha gerektirecek."
STRINGS.SKIN_QUOTES.wanda_bishop_d = "Bu maç birkaç erteleme daha gerektirecek."
STRINGS.SKIN_QUOTES.wanda_bishop_p = "Bu maç birkaç erteleme daha gerektirecek."
STRINGS.SKIN_QUOTES.wanda_formal = "Hiçbir şey dakiklikten daha şık değildir."
STRINGS.SKIN_QUOTES.wanda_ice = "Ah kahretsin, bu sefer kendimi nereye attım?"
STRINGS.SKIN_QUOTES.wanda_lunar = "Geleceğim ayın evrelerinde kendini gösterecek."
STRINGS.SKIN_QUOTES.wanda_masquerade = "Yıldız ışığı geçmişten gelen bir patlamadır."
STRINGS.SKIN_QUOTES.wanda_nature = "Ormanın derinliklerinde zaman daha yavaş akıyor gibi."
STRINGS.SKIN_QUOTES.wanda_rose = "Sanırım arada bir durup gülleri koklamaya zaman ayırmalıyım."
